using System;

class Animal {
    public string Name { get; set; }
    public void Breathe() => Console.WriteLine($"{Name} breathes");
}

class Dog : Animal {
    public void Bark() => Console.WriteLine($"{Name} says: Woof!");
}

class Program {
    static void Main() {
        var dog = new Dog { Name = "Rex" };
        dog.Breathe(); // inherited
        dog.Bark();    // own method
    }
}

using System;

class Shape {
    public virtual double Area() => 0;
    public virtual string Describe() => $"Shape with area {Area():F2}";
}

class Circle : Shape {
    public double Radius { get; }
    public Circle(double r) { Radius = r; }
    public override double Area() => Math.PI * Radius * Radius;
}

class Program {
    static void Main() {
        Shape s = new Circle(5);
        Console.WriteLine(s.Area());
        Console.WriteLine(s.Describe());
    }
}

using System;

class Animal {
    public string Name { get; }
    public Animal(string name) { Name = name; }
    public virtual string Speak() => $"{Name} makes a sound";
}

class Cat : Animal {
    public Cat(string name) : base(name) {} // call base constructor
    public override string Speak() => base.Speak() + " (meow)";
}

class Program {
    static void Main() {
        var c = new Cat("Whiskers");
        Console.WriteLine(c.Speak());
    }
}

using System;

abstract class Shape {
    public abstract double Area();
    public void Print() => Console.WriteLine($"Area: {Area():F2}");
}

class Square : Shape {
    private double side;
    public Square(double s) { side = s; }
    public override double Area() => side * side;
}

class Triangle : Shape {
    private double b, h;
    public Triangle(double b, double h) { this.b = b; this.h = h; }
    public override double Area() => 0.5 * b * h;
}

class Program {
    static void Main() {
        Shape[] shapes = { new Square(4), new Triangle(6, 3) };
        foreach (var s in shapes) s.Print();
    }
}

