using System;

class Animal { public string Name { get; set; } }
class Dog : Animal { public void Bark() => Console.WriteLine("Woof"); }
class Cat : Animal { public void Meow() => Console.WriteLine("Meow"); }

class Program {
    static void Main() {
        Animal[] animals = { new Dog { Name = "Rex" }, new Cat { Name = "Luna" } };
        foreach (var a in animals) {
            if (a is Dog d) d.Bark();
            else if (a is Cat c) c.Meow();
        }
    }
}

using System;
using System.Collections.Generic;

class Animal {
    public string Name { get; set; }
    public virtual string Sound() => "...";
}
class Dog : Animal { public override string Sound() => "Woof"; }
class Cat : Animal { public override string Sound() => "Meow"; }
class Cow : Animal { public override string Sound() => "Moo"; }

class Program {
    static void Main() {
        var farm = new List<Animal> {
            new Dog { Name = "Rex" },
            new Cat { Name = "Luna" },
            new Cow { Name = "Bessie" }
        };
        foreach (var a in farm) {
            Console.WriteLine($"{a.Name}: {a.Sound()}");
        }
    }
}

